svg.script:
(function(){
var s=document.querySelector('svg'),n=0;
var shown=new Set();
s.querySelectorAll('.path-animate').forEach(function(p){
var l=p.getTotalLength();p.style.setProperty('--path-length',l);
});
s.addEventListener('click',function(e){
e.stopPropagation();n=(n+1)%6;
if(n===0){shown.forEach(function(el){el.classList.remove('show');});shown.clear();return;}
var els=[];
if(n>=1)els.push('.regelstrecke');
if(n>=2)els.push('.messglied','.feedback-path');
if(n>=3)els.push('.wunschtemperatur','.arrow-circle','.circle','.short-line');
if(n>=4)els.push('.regler','.arrow-square','.square');
if(n>=5)els.push('.forward-path','.steller','.stellglied');
els.forEach(function(sel){s.querySelectorAll(sel).forEach(function(el){if(!shown.has(el)){el.classList.add('show');shown.add(el);}});});
});
s.style.cursor='pointer';
})();
